// ━━━ Logo (theme-aware, uses actual brand images with transparent bg) ━━━━━━━
const LOGO_LIGHT = "data:image/png;base64,";
const LOGO_DARK = "data:image/png;base64,";
const ICO_TPN = "data:image/png;base64,";
const ICO_GIR = "data:image/png;base64,";
const ICO_NUT = "data:image/png;base64,";
const LOGO_LIGHT_C = "data:image/png;base64,";
const LOGO_DARK_C = "data:image/png;base64,";
function Logo({ T, width = 200, compact = false }) {
  const src = compact ? (T === TH.dark ? LOGO_DARK_C : LOGO_LIGHT_C) : (T === TH.dark ? LOGO_DARK : LOGO_LIGHT);
  return <img src={src} alt="NeoFORT" style={{ width, height: "auto" }} />;
}
