        fm: ov.fm ?? nut.fm,
        hm: ov.hm ?? nut.hm,                              // HMF values — always original
        ptf: ov.ptf ?? (PTF_PRENAN[nut.k] ?? nut.hm),    // PTF values — from PreNan or saved overrides
