    mviVitePerMl: nutOv?.__supDef?.mviVitePerMl ?? 5,
    mviZnPerMl: nutOv?.__supDef?.mviZnPerMl ?? 2.5,
    mviRiboPerMl: nutOv?.__supDef?.mviRiboPerMl ?? 1,
